contracts/adapters/HyperliquidAdapter.so.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "../interfaces/IPerpExchange.sol";

/**
 * @title HyperliquidAdapter
 * @notice IPerpExchange adapter for the real Hyperliquid L1 / Arbitrum bridge.
 *
 * ── How Hyperliquid deposits work ────────────────────────────────────────────
 * Hyperliquid runs on its own L1 chain. Depositing USDC is a pure on-chain action:
 * call `USDC.transfer(bridge, amount)` and HL validators credit this contract's
 * address on the HL L1 within ~1 minute.
 *
 * Bridge2 on Arbitrum One: 0x2Df1c51E09aECF9cacB7bc98cB1742757f163dF7
 * USDC (native) on Arbitrum: 0xaf88d065e77c8cC2239327C5EDb3A432268e5831
 * Minimum deposit: 5 USDC.
 *
 * ── How Hyperliquid withdrawals work ─────────────────────────────────────────
 * Withdrawals are initiated off-chain via the HL REST API (an EIP-712 signed
 * `withdraw3` action). Validators process it and bridge USDC back to Arbitrum
 * in 3–4 minutes. The destination can be any Arbitrum address — the bot should
 * specify this adapter contract's address so USDC arrives here and can be
 * forwarded on to KashYield via withdrawCollateral().
 *
 * ── How trading works (spot and perp) ────────────────────────────────────────
 * All trading on Hyperliquid is off-chain via the HL REST API. There are no
 * on-chain Arbitrum transactions for spot buys/sells or perp open/close.
 *
 * This means tradeSpot(), openPerpPosition(), and closePerpPosition() are
 * *recording stubs* — they emit events so the bot can track call history,
 * but they do not trigger any HL action. The bot must:
 *   1. Execute the trade via the HL API.
 *   2. Call syncBalances() and/or syncPosition() on this adapter to update
 *      the on-chain state that KashYield reads.
 *
 * ── HL agent authorisation ────────────────────────────────────────────────────
 * The HL L1 account for this adapter is this contract's own Arbitrum address.
 * Because the adapter is a smart contract it cannot directly sign HL API
 * payloads. The bot operator must authorise the bot wallet as an HL "agent"
 * for this adapter's address via the HL REST API:
 *
 *   POST /exchange   { "action": { "type": "approveAgent", ... }, "signature": ... }
 *
 * This requires a one-time off-chain signature from a wallet that controls the
 * adapter's HL account. If the adapter contract's address was freshly credited
 * by a deposit and has never signed any HL action, the bot operator should use
 * the adapter owner wallet to create this signature via an EIP-1271-compatible
 * flow or by temporarily holding the "master key" for that address before the
 * adapter contract is deployed (create2 pre-authorisation pattern).
 *
 * In practice, the simplest setup for early-stage deployment is to let the
 * bot wallet be the HL account directly (by depositing from the bot wallet's
 * own address rather than through this adapter). See `directDepositMode` below.
 *
 * ── Direct-deposit mode ───────────────────────────────────────────────────────
 * When `directDepositMode` is true, depositCollateral() forwards USDC to the
 * configured `hlAccount` address (the bot wallet EOA) instead of sending it to
 * the bridge directly. The bot wallet then deposits to HL from its own address,
 * making the bot wallet the HL account. Withdrawals from HL are made directly
 * to this adapter's address (the bot specifies adapter as destination).
 *
 * directDepositMode = false: adapter address is the HL account (production ideal)
 * directDepositMode = true:  bot EOA is the HL account (simpler agent setup)
 *
 * ── Access control ────────────────────────────────────────────────────────────
 * Capital-movement functions (depositCollateral, withdrawCollateral, tradeSpot,
 * openPerpPosition, closePerpPosition, cancelOrder) are restricted to:
 *   - kashYieldAddress (the KashYield contract that owns this adapter)
 *   - owner (deployer / governance multisig for manual operations)
 * State-sync functions (syncBalances, syncPosition) may be called by `owner` or,
 * when configured via setOperator(), by `operator` (bot worker). If operator is
 * address(0), only the owner may sync (backwards compatible).
 */
contract HyperliquidAdapter is IPerpExchange {
    using SafeERC20 for IERC20;

    /// @notice HL Bridge2 on Arbitrum One: 0x2Df1c51E09aECF9cacB7bc98cB1742757f163dF7
    address public immutable hlBridgeAddress;
    /// @notice Native USDC on Arbitrum One: 0xaf88d065e77c8cC2239327C5EDb3A432268e5831
    address public immutable usdcAddress;
    /// @notice wBTC address for the BTC product; address(0) for the ETH product.
    address public immutable assetAddress;
    /// @notice True if this adapter serves the ETH yield product.
    bool public immutable isEthAsset;
    /// @notice The KashYield contract authorised to call capital-movement functions.
    address public immutable kashYieldAddress;

    address public owner;
    address public pendingOwner;

    /// @notice Optional ExchangeFacade (or other vault delegate) authorised for capital-movement calls.
    address public authorizedCaller;

    /// @notice Bot / worker authorised to call syncBalances and syncPosition when non-zero.
    address public operator;

    /// @notice When true, depositCollateral forwards USDC to hlAccount (bot EOA as HL account).
    /// When false, USDC is sent directly to the bridge (adapter address as HL account).
    bool public directDepositMode;
    /// @notice Bot wallet EOA used when directDepositMode = true, or for reference.
    address public hlAccount;

    // ── Bot-maintained state ──────────────────────────────────────────────────
    // HL is an off-chain system; on-chain state is kept in sync by the bot calling
    // syncBalances() / syncPosition() after each HL API operation.

    /// @notice USDC held in this adapter's HL spot wallet (6 decimals).
    uint256 public usdcBalance;
    /// @notice ETH or wBTC held in this adapter's HL spot wallet (18-dec internal units).
    uint256 public assetBalance;

    struct Position {
        uint256 size;       // 18-dec
        uint256 collateral; // always 0 on HL (USDC margin is pooled)
        uint256 entryPrice; // 18-dec USD
        bool    isLong;
        bool    isActive;
    }
    mapping(string => Position) public positions;

    event AdapterCall(string action, uint256 amount);
    /// @notice USDC forwarded to `to` after capping to adapter balance (requested vs actual).
    event HyperliquidUsdcWithdrawn(address indexed to, uint256 amountRequested, uint256 amountTransferred);
    event DirectDepositModeUpdated(bool enabled, address hlAccount);
    event OwnershipTransferStarted(address indexed previousOwner, address indexed newOwner);
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);
    event OperatorUpdated(address indexed previousOperator, address indexed newOperator);
    event AuthorizedCallerUpdated(address indexed caller);
    event BalancesSynced(uint256 usdcBalance, uint256 assetBalance);
    event PositionSynced(string symbol, uint256 size, uint256 entryPrice, bool isActive);

    bytes4 private constant ERC1271_MAGIC = 0x1626ba7e;

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner");
        _;
    }

    modifier onlyOwnerOrOperator() {
        address snd = msg.sender;
        require(
            snd == owner || (operator != address(0) && snd == operator),
            "Only owner or operator"
        );
        _;
    }

    /// @dev KashYield, ExchangeFacade (when set), or owner (ops scripts / manual ops).
    modifier onlyAuthorized() {
        address snd = msg.sender;
        require(
            snd == kashYieldAddress || snd == owner
                || (authorizedCaller != address(0) && snd == authorizedCaller),
            "Unauthorized"
        );
        _;
    }

    constructor(
        address _hlBridgeAddress,
        address _usdcAddress,
        address _assetAddress,
        bool    _isEthAsset,
        address _kashYieldAddress
    ) {
        require(_kashYieldAddress != address(0), "kashYieldAddress required");
        hlBridgeAddress   = _hlBridgeAddress;
        usdcAddress       = _usdcAddress;
        assetAddress      = _assetAddress;
        isEthAsset        = _isEthAsset;
        kashYieldAddress  = _kashYieldAddress;
        owner             = msg.sender;
        directDepositMode = false;
    }

    // ── Ownership (two-step) ──────────────────────────────────────────────────

    function transferOwnership(address newOwner) external onlyOwner {
        pendingOwner = newOwner;
        emit OwnershipTransferStarted(owner, newOwner);
    }
    function acceptOwnership() external {
        require(msg.sender == pendingOwner, "Not pending owner");
        emit OwnershipTransferred(owner, pendingOwner);
        owner        = pendingOwner;
        pendingOwner = address(0);
    }

    // ── Configuration ─────────────────────────────────────────────────────────

    /// @notice Toggle between bridge-direct and forwarded-to-EOA deposit modes.
    function setDirectDepositMode(bool enabled, address _hlAccount) external onlyOwner {
        directDepositMode = enabled;
        hlAccount = _hlAccount;
        emit DirectDepositModeUpdated(enabled, _hlAccount);
    }

    /// @notice Authorise a bot EOA to refresh on-chain HL mirrors (sync only).
    /// @param newOperator Pass address(0) to revoke operator and return to owner-only sync.
    function setOperator(address newOperator) external onlyOwner {
        emit OperatorUpdated(operator, newOperator);
        operator = newOperator;
    }

    /// @notice Authorise ExchangeFacade (or delegate) to call capital-movement functions.
    function setAuthorizedCaller(address caller) external onlyOwner {
        authorizedCaller = caller;
        emit AuthorizedCallerUpdated(caller);
    }

    // ── Capital movement ──────────────────────────────────────────────────────

    /**
     * @inheritdoc IPerpExchange
     *
     * @dev On mainnet, only USDC is accepted by Hyperliquid.
     *
     * directDepositMode = false (default, adapter is HL account):
     *   Sends USDC directly to the HL Bridge2 contract. HL validators credit
     *   this adapter's Arbitrum address on the HL L1 within ~1 minute.
     *   Requires prior off-chain HL agent authorisation for the bot wallet.
     *
     * directDepositMode = true (bot EOA is HL account):
     *   Forwards USDC to hlAccount (bot wallet). Bot deposits to bridge from
     *   its own EOA, becoming the HL account holder without agent setup.
     */
    function depositCollateral(address token, uint256 amount) external override onlyAuthorized {
        require(token == usdcAddress, "HL only accepts USDC");
        IERC20(token).safeTransferFrom(msg.sender, address(this), amount);
        if (directDepositMode) {
            require(hlAccount != address(0), "hlAccount not set");
            IERC20(token).safeTransfer(hlAccount, amount);
        } else {
            // Direct bridge deposit: HL credits this adapter's address on L1.
            IERC20(token).safeTransfer(hlBridgeAddress, amount);
        }
        usdcBalance += amount;
        emit AdapterCall("depositCollateral", amount);
    }

    /**
     * @inheritdoc IPerpExchange
     *
     * @dev The bot must first initiate the HL withdrawal via the HL REST API,
     * specifying this adapter's Arbitrum address as the destination. USDC arrives
     * here in 3–4 minutes. This function transfers however much has actually
     * settled (capped to the real ERC-20 balance) rather than reverting if the
     * bridged amount is slightly different from the requested amount.
     *
     * If the withdrawal was sent directly to KashYield (rather than this adapter),
     * call this function with amount = 0 to just update the tracked balance.
     */
    function withdrawCollateral(address token, uint256 amount) external override onlyAuthorized returns (uint256 amountTransferred) {
        require(token == usdcAddress, "HL only withdraws USDC");
        uint256 requested = amount;
        uint256 bal = IERC20(token).balanceOf(address(this));
        if (amount > bal) amount = bal; // cap to what has actually settled
        amountTransferred = amount;
        if (amount > 0) {
            IERC20(token).safeTransfer(msg.sender, amount);
        }
        if (usdcBalance >= amount) usdcBalance -= amount;
        emit HyperliquidUsdcWithdrawn(msg.sender, requested, amountTransferred);
        emit AdapterCall("withdrawCollateral", amountTransferred);
    }

    // ── Spot trading (no-op stubs) ────────────────────────────────────────────
    //
    // On real HL, spot trades are off-chain API calls. These stubs emit events
    // for audit purposes only. The bot executes the actual trade via the HL API,
    // then calls syncBalances() to record the result on-chain.

    /// @inheritdoc IPerpExchange
    function tradeSpot(
        address /*tokenIn*/,
        address /*tokenOut*/,
        uint256 amountIn
    ) external payable override onlyAuthorized returns (uint256) {
        emit AdapterCall("tradeSpot", amountIn);
        return 0;
    }

    /**
     * @inheritdoc IPerpExchange
     * @dev HL does not allow direct ETH/wBTC withdrawals — only USDC exits the bridge.
     * Use withdrawCollateral() for USDC. Swap excess USDC to ETH/wBTC via Uniswap
     * (swapFromUsdc on KashYieldETH) if additional collateral is needed.
     */
    function withdrawAsset(uint256) external pure override {
        revert("HL withdrawals are USDC-only; use withdrawCollateral");
    }

    // ── Perp positions (no-op stubs) ──────────────────────────────────────────
    //
    // All perp operations are off-chain via the HL REST API. After executing,
    // the bot calls syncPosition() to record the new state on-chain.

    /// @inheritdoc IPerpExchange
    function openPerpPosition(string calldata /*symbol*/, uint256 size, bool /*isLong*/) external override onlyAuthorized {
        emit AdapterCall("openPerpPosition", size);
    }
    /// @inheritdoc IPerpExchange
    function closePerpPosition(string calldata /*symbol*/) external override onlyAuthorized {
        emit AdapterCall("closePerpPosition", 0);
    }
    /// @inheritdoc IPerpExchange
    function closePerpPosition(string calldata /*symbol*/, uint256 closeSize) external override onlyAuthorized {
        emit AdapterCall("closePerpPosition", closeSize);
    }
    /// @inheritdoc IPerpExchange
    function cancelOrder(bytes32) external override onlyAuthorized {
        emit AdapterCall("cancelOrder", 0);
    }

    // ── Bot state-sync functions ──────────────────────────────────────────────
    //
    // After every HL API operation the bot calls these to keep on-chain state
    // accurate. KashYield view calls (getHyperliquidSpotBalance etc.) read these.

    /**
     * @notice Update USDC and asset balances after any HL trade or transfer.
     * @param newUsdcBalance  Current USDC balance in HL spot wallet (6 decimals).
     * @param newAssetBalance Current ETH/wBTC balance in HL spot wallet (18-dec).
     */
    function syncBalances(uint256 newUsdcBalance, uint256 newAssetBalance) external onlyOwnerOrOperator {
        usdcBalance  = newUsdcBalance;
        assetBalance = newAssetBalance;
        emit BalancesSynced(newUsdcBalance, newAssetBalance);
    }

    /**
     * @notice Update a perp position after open or (partial) close.
     * @param symbol     Asset symbol, e.g. "ETH" or "BTC".
     * @param size       Remaining position size (18-dec). Pass 0 to mark closed.
     * @param entryPrice Entry price in USD (18-dec). Pass 0 when closing.
     * @param isActive   True if the position is still open.
     */
    function syncPosition(
        string calldata symbol,
        uint256 size,
        uint256 entryPrice,
        bool isActive
    ) external onlyOwnerOrOperator {
        positions[symbol] = Position({
            size:       size,
            collateral: 0,
            entryPrice: entryPrice,
            isLong:     false,
            isActive:   isActive
        });
        emit PositionSynced(symbol, size, entryPrice, isActive);
    }

    // ── Views (return bot-synced state) ──────────────────────────────────────

    /// @inheritdoc IPerpExchange
    function getSpotBalance() external view override returns (uint256) {
        return usdcBalance;
    }

    /// @inheritdoc IPerpExchange
    function getAssetBalance() external view override returns (uint256) {
        return assetBalance;
    }

    /// @inheritdoc IPerpExchange
    function getPosition(string calldata symbol) external view override returns (
        uint256 size,
        uint256 collateral,
        uint256 entryPrice,
        bool    isLong,
        bool    isActive
    ) {
        Position storage p = positions[symbol];
        return (p.size, p.collateral, p.entryPrice, p.isLong, p.isActive);
    }

    /// @inheritdoc IPerpExchange
    /// @dev HL order management is entirely off-chain; there are no on-chain order IDs.
    function getOpenOrderIds() external pure override returns (bytes32[] memory) {
        return new bytes32[](0);
    }

    /**
     * @notice ERC-1271: owner-authorized signatures for Hyperliquid REST actions when
     *         this adapter is the HL master account (directDepositMode=false).
     */
    function isValidSignature(bytes32 hash, bytes memory signature) external view returns (bytes4) {
        (address recovered, ECDSA.RecoverError err,) = ECDSA.tryRecover(hash, signature);
        if (err == ECDSA.RecoverError.NoError && recovered == owner) {
            return ERC1271_MAGIC;
        }
        return 0xffffffff;
    }
}

contracts/adapters/UniswapV3Adapter.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "../interfaces/ISpotDex.sol";

/// @dev Uniswap **SwapRouter02** `exactInputSingle` (IV3SwapRouter) — **no `deadline` field**.
/// SwapRouter01 (`0xE592…`) used a larger struct with `deadline`; encoding that against Router02
/// mis-aligns ABI slots and swaps revert with empty data. Production Arbitrum uses Router02
/// (`0x68b3465833fb72A70ecDF485E0e4C7bD8665Fc45`).
interface IUniswapV3SwapRouter {
    struct ExactInputSingleParams {
        address tokenIn;
        address tokenOut;
        uint24 fee;
        address recipient;
        uint256 amountIn;
        uint256 amountOutMinimum;
        uint160 sqrtPriceLimitX96;
    }

    function exactInputSingle(ExactInputSingleParams calldata params) external payable returns (uint256 amountOut);
}

/// @dev WETH interface for native ETH wrapping.
interface IWETH9 is IERC20 {
    function deposit() external payable;
    function withdraw(uint256 amount) external;
}

/**
 * @title UniswapV3Adapter
 * @notice ISpotDex adapter for Uniswap V3. Supports wBTC ↔ USDC and ETH ↔ USDC swaps.
 *
 * Used by KashYieldBtc/ETH to:
 *   - Swap ETH/wBTC → USDC when perp P&L doesn't fully cover the Aave debt (rising price)
 *   - Swap USDC → ETH/wBTC when short profits exceed Aave debt and extra collateral is needed (falling price)
 *
 * The fee tier per pool is configurable (default 0.05% = 500), which matches the main
 * WETH/USDC and wBTC/USDC pools on Arbitrum. Override per pair if needed.
 *
 * Pass **SwapRouter02** only (do not use SwapRouter01 — different `exactInputSingle` struct).
 *   Arbitrum One (mainnet): 0x68b3465833fb72A70ecDF485E0e4C7bD8665Fc45
 *   Arbitrum Sepolia:       0x101F443B4d1b059569D643917553c771E1b9663E
 *
 * WETH addresses:
 *   Arbitrum One:    0x82aF49447D8a07e3bd95BD0d56f35241523fBab1
 *   Arbitrum Sepolia: 0x980B62Da83eFf3D4576C647993b0c1D7faf17c73
 */
contract UniswapV3Adapter is ISpotDex {
    using SafeERC20 for IERC20;

    IUniswapV3SwapRouter public immutable swapRouter;
    address public immutable wethAddress; // Wrapped ETH for native ETH swaps

    address public owner;
    address public pendingOwner;

    /// @notice Default fee tier (basis points * 100). 500 = 0.05%, 3000 = 0.3%, 10000 = 1%.
    /// 0.05% is the primary fee tier for WETH/USDC and wBTC/USDC on Arbitrum mainnet.
    uint24 public defaultFeeTier = 500;
    /// @notice Override fee tier per tokenIn+tokenOut pair (0 = use defaultFeeTier).
    mapping(address => mapping(address => uint24)) public feeTierOverride;

    event SwapExecuted(address indexed tokenIn, address indexed tokenOut, uint256 amountIn, uint256 amountOut);

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner");
        _;
    }

    constructor(address _swapRouter, address _wethAddress) {
        swapRouter  = IUniswapV3SwapRouter(_swapRouter);
        wethAddress = _wethAddress;
        owner = msg.sender;
    }

    function transferOwnership(address newOwner) external onlyOwner {
        pendingOwner = newOwner;
    }
    function acceptOwnership() external {
        require(msg.sender == pendingOwner, "Not pending owner");
        owner = pendingOwner;
        pendingOwner = address(0);
    }

    /// @notice Set a specific fee tier for a tokenIn → tokenOut pair.
    function setFeeTierOverride(address tokenIn, address tokenOut, uint24 fee) external onlyOwner {
        feeTierOverride[tokenIn][tokenOut] = fee;
    }

    function setDefaultFeeTier(uint24 fee) external onlyOwner {
        defaultFeeTier = fee;
    }

    // ── ISpotDex ─────────────────────────────────────────────────────────

    /// @inheritdoc ISpotDex
    function swapExactIn(
        address tokenIn,
        address tokenOut,
        uint256 amountIn,
        uint256 minAmountOut,
        address recipient
    ) external payable override returns (uint256 amountOut) {
        address effectiveTokenIn  = tokenIn;
        address effectiveTokenOut = tokenOut;

        if (tokenIn == address(0)) {
            // Native ETH in → wrap to WETH, swap WETH → tokenOut
            require(msg.value == amountIn, "ETH amount mismatch");
            IWETH9(wethAddress).deposit{value: amountIn}();
            effectiveTokenIn = wethAddress;
        } else {
            IERC20(tokenIn).safeTransferFrom(msg.sender, address(this), amountIn);
        }

        // ETH out → swap to WETH here, unwrap after
        bool nativeEthOut = tokenOut == address(0);
        if (nativeEthOut) {
            effectiveTokenOut = wethAddress;
        }

        IERC20(effectiveTokenIn).forceApprove(address(swapRouter), amountIn);

        uint24 fee = feeTierOverride[effectiveTokenIn][effectiveTokenOut];
        if (fee == 0) fee = defaultFeeTier;

        IUniswapV3SwapRouter.ExactInputSingleParams memory params = IUniswapV3SwapRouter.ExactInputSingleParams({
            tokenIn: effectiveTokenIn,
            tokenOut: effectiveTokenOut,
            fee: fee,
            recipient: nativeEthOut ? address(this) : recipient,
            amountIn: amountIn,
            amountOutMinimum: minAmountOut,
            sqrtPriceLimitX96: 0
        });

        amountOut = swapRouter.exactInputSingle(params);

        if (nativeEthOut) {
            // Unwrap WETH → native ETH and forward to the original recipient
            IWETH9(wethAddress).withdraw(amountOut);
            (bool ok,) = recipient.call{value: amountOut}("");
            require(ok, "ETH transfer failed");
        }

        emit SwapExecuted(tokenIn, tokenOut, amountIn, amountOut);
    }

    receive() external payable {}
}

contracts/ExchangeFacade.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.28;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "./libraries/ProtocolActionCodes.sol";
import "./interfaces/IPerpExchange.sol";

/// @notice Standalone perp exchange registry and HL operation facade (deployed separately from vault).
contract ExchangeFacade {
    using SafeERC20 for IERC20;

    address public owner;
    address public botAddress;
    address public keeperRegistry;
    address public immutable usdcAddress;
    address public immutable primaryAsset;
    address public immutable kashYieldAddress;

    mapping(string => address) public perpExchanges;
    string public activePerpExchange;

    bool private anyAdapterConfirmed;
    mapping(string => address) private pendingAdapters;
    mapping(string => uint256) public adapterReadyAt;
    uint256 public exchangeSwitchDelay = 24 hours;

    event ExchangeRegistered(string indexed name, address adapter);
    event AdapterProposed(string indexed name, address adapter, uint256 readyAt);
    event ExchangeSwitchConfirmed(string indexed name, address adapter);
    event ProtocolInteraction(uint8 indexed action, address indexed asset, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner");
        _;
    }

    modifier onlyBotOrKeeper() {
        require(msg.sender == botAddress || msg.sender == keeperRegistry, "Only bot/keeper");
        _;
    }

    constructor(address _owner, address _bot, address _usdc, address _primaryAsset, address _kashYield) {
        owner = _owner;
        botAddress = _bot;
        usdcAddress = _usdc;
        primaryAsset = _primaryAsset;
        kashYieldAddress = _kashYield;
    }

    function setBotAddress(address _bot) external onlyOwner { botAddress = _bot; }
    function setKeeperRegistry(address _keeper) external onlyOwner { keeperRegistry = _keeper; }

    function setPerpExchange(string calldata name, address adapter) external onlyOwner {
        require(adapter != address(0), "Invalid adapter");
        if (!anyAdapterConfirmed) {
            perpExchanges[name] = adapter;
            anyAdapterConfirmed = true;
            emit ExchangeRegistered(name, adapter);
            return;
        }
        pendingAdapters[name] = adapter;
        adapterReadyAt[name] = block.timestamp + exchangeSwitchDelay;
        emit AdapterProposed(name, adapter, adapterReadyAt[name]);
    }

    function confirmPerpExchange(string calldata name) external onlyOwner {
        require(adapterReadyAt[name] != 0 && block.timestamp >= adapterReadyAt[name], "Timelock");
        perpExchanges[name] = pendingAdapters[name];
        emit ExchangeRegistered(name, perpExchanges[name]);
        delete pendingAdapters[name];
        delete adapterReadyAt[name];
    }

    function setActivePerpExchange(string calldata name) external onlyOwner {
        require(perpExchanges[name] != address(0), "Not registered");
        activePerpExchange = name;
        emit ExchangeSwitchConfirmed(name, perpExchanges[name]);
    }

    function setHyperliquid(address adapter) external onlyOwner {
        require(adapter != address(0), "Invalid adapter");
        if (!anyAdapterConfirmed) {
            perpExchanges["HL"] = adapter;
            anyAdapterConfirmed = true;
            emit ExchangeRegistered("HL", adapter);
            return;
        }
        pendingAdapters["HL"] = adapter;
        adapterReadyAt["HL"] = block.timestamp + exchangeSwitchDelay;
        emit AdapterProposed("HL", adapter, adapterReadyAt["HL"]);
    }
    function hyperliquidAddress() external view returns (address) { return perpExchanges["HL"]; }

    function depositToHyperliquid(uint256 amount) external onlyBotOrKeeper {
        address adapter = _activePerpAdapter();
        IERC20(usdcAddress).safeTransferFrom(kashYieldAddress, address(this), amount);
        IERC20(usdcAddress).forceApprove(adapter, amount);
        IPerpExchange(adapter).depositCollateral(usdcAddress, amount);
        emit ProtocolInteraction(ProtocolActionCodes.EXCHANGE_DEPOSIT, usdcAddress, amount);
    }

    function withdrawFromHyperliquid(uint256 amount) external onlyBotOrKeeper {
        address adapter = _activePerpAdapter();
        uint256 transferred = IPerpExchange(adapter).withdrawCollateral(usdcAddress, amount);
        IERC20(usdcAddress).safeTransfer(kashYieldAddress, transferred);
        emit ProtocolInteraction(ProtocolActionCodes.EXCHANGE_WITHDRAW, usdcAddress, transferred);
    }

    function withdrawAssetFromHyperliquid(uint256 amount) external onlyBotOrKeeper {
        address adapter = _activePerpAdapter();
        IPerpExchange(adapter).withdrawAsset(amount);
        emit ProtocolInteraction(ProtocolActionCodes.EXCHANGE_WITHDRAW_ASSET, primaryAsset, amount);
    }

    function addCollateralToHyperliquid(uint256 amount) external onlyBotOrKeeper {
        address adapter = _activePerpAdapter();
        IERC20(usdcAddress).safeTransferFrom(kashYieldAddress, address(this), amount);
        IERC20(usdcAddress).forceApprove(adapter, amount);
        IPerpExchange(adapter).depositCollateral(usdcAddress, amount);
        emit ProtocolInteraction(ProtocolActionCodes.EXCHANGE_ADD_COLLATERAL, usdcAddress, amount);
    }

    function openShort(string calldata symbol, uint256 size) external onlyBotOrKeeper {
        IPerpExchange(_activePerpAdapter()).openPerpPosition(symbol, size, false);
        emit ProtocolInteraction(ProtocolActionCodes.EXCHANGE_OPEN_SHORT, primaryAsset, size);
    }

    function closeShort(string calldata symbol) external onlyBotOrKeeper {
        IPerpExchange(_activePerpAdapter()).closePerpPosition(symbol);
        emit ProtocolInteraction(ProtocolActionCodes.EXCHANGE_CLOSE_SHORT, primaryAsset, 0);
    }

    function closeShort(string calldata symbol, uint256 closeSize) external onlyBotOrKeeper {
        IPerpExchange(_activePerpAdapter()).closePerpPosition(symbol, closeSize);
        emit ProtocolInteraction(ProtocolActionCodes.EXCHANGE_CLOSE_SHORT, primaryAsset, closeSize);
    }

    function spotBuyOnHyperliquid(uint256 usdcAmount) external onlyBotOrKeeper {
        address adapter = _activePerpAdapter();
        IERC20(usdcAddress).safeTransferFrom(kashYieldAddress, address(this), usdcAmount);
        IERC20(usdcAddress).forceApprove(adapter, usdcAmount);
        uint256 out = IPerpExchange(adapter).tradeSpot(usdcAddress, primaryAsset, usdcAmount);
        emit ProtocolInteraction(ProtocolActionCodes.EXCHANGE_SPOT_BUY, primaryAsset, out);
    }

    function spotSellOnHyperliquid(uint256 amount) external onlyBotOrKeeper {
        uint256 out = IPerpExchange(_activePerpAdapter()).tradeSpot(primaryAsset, usdcAddress, amount);
        emit ProtocolInteraction(ProtocolActionCodes.EXCHANGE_SPOT_SELL, usdcAddress, out);
    }

    function cancelHyperliquidOrder(bytes32 orderId) external onlyBotOrKeeper {
        IPerpExchange(_activePerpAdapter()).cancelOrder(orderId);
        emit ProtocolInteraction(ProtocolActionCodes.EXCHANGE_CANCEL_ORDER, primaryAsset, 0);
    }

    function getHyperliquidSpotBalance() external view returns (uint256) {
        address adapter = perpExchanges[activePerpExchange];
        return adapter == address(0) ? 0 : IPerpExchange(adapter).getSpotBalance();
    }

    function getExchangeAssetBalance() external view returns (uint256) {
        address adapter = perpExchanges[activePerpExchange];
        return adapter == address(0) ? 0 : IPerpExchange(adapter).getAssetBalance();
    }

    function getHyperliquidPosition(string calldata symbol) external view returns (
        uint256 size, uint256 collateral, uint256 entryPrice, bool isLong, bool isActive
    ) {
        address adapter = perpExchanges[activePerpExchange];
        if (adapter == address(0)) return (0, 0, 0, false, false);
        return IPerpExchange(adapter).getPosition(symbol);
    }

    function _activePerpAdapter() internal view returns (address adapter) {
        adapter = perpExchanges[activePerpExchange];
        require(adapter != address(0), "No active exchange");
    }
}

contracts/interfaces/IPerpExchange.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.28;

/**
 * @title IPerpExchange
 * @notice Shared interface for perpetual exchange adapters (e.g. HyperliquidAdapter).
 *
 * Each adapter is a standalone contract that translates these standardised calls into the
 * underlying exchange's native API.  The main KashYield contracts hold an exchange registry
 * (mapping(string => address) perpExchanges) and route all calls through this interface,
 * making them completely exchange-agnostic.
 *
 * Adding a new exchange in the future requires only:
 *   1. Deploying a new adapter that implements this interface.
 *   2. Calling setPerpExchange("NAME", adapterAddress) on the main contract.
 *   3. (After the adapter-registration timelock) Calling confirmPerpExchange().
 *   No changes to the main contracts are needed.
 *
 * The adapter IS the on-exchange account: all positions and balances are tracked against
 * the adapter's own address on the underlying exchange.
 */
interface IPerpExchange {

    // ── Capital movement ──────────────────────────────────────────────────

    /// @notice Deposit stable collateral (USDC) into the exchange spot wallet.
    /// Caller must approve this adapter for `amount` of `token` beforehand.
    function depositCollateral(address token, uint256 amount) external;

    /// @notice Withdraw stable collateral (USDC) from the exchange spot wallet to msg.sender.
    /// @return amountTransferred USDC actually transferred (may be less than `amount` if the adapter caps to balance).
    function withdrawCollateral(address token, uint256 amount) external returns (uint256 amountTransferred);

    // ── Spot trading ──────────────────────────────────────────────────────

    /// @notice Swap tokenIn for tokenOut on the exchange spot market.
    /// For ETH-in swaps msg.value must equal amountIn and tokenIn must be address(0).
    /// For ERC-20 inputs, caller must approve this adapter for `amountIn` beforehand.
    /// @return amountOut Amount of tokenOut received (0 if credited to internal ledger).
    function tradeSpot(
        address tokenIn,
        address tokenOut,
        uint256 amountIn
    ) external payable returns (uint256 amountOut);

    /// @notice Withdraw the held asset (BTC or ETH) from the exchange back to msg.sender
    /// as a real token/ETH.  amount is in 18-dec internal units.
    /// For wBTC this is converted to 8-dec on transfer (amount / 1e10).
    function withdrawAsset(uint256 amount) external;

    // ── Perp positions ────────────────────────────────────────────────────

    function openPerpPosition(string calldata symbol, uint256 size, bool isLong) external;
    function closePerpPosition(string calldata symbol) external;
    function closePerpPosition(string calldata symbol, uint256 closeSize) external;
    function cancelOrder(bytes32 orderId) external;

    // ── Views ─────────────────────────────────────────────────────────────

    /// @notice USDC balance held in the exchange spot wallet by this adapter (6-dec).
    function getSpotBalance() external view returns (uint256);

    /// @notice BTC or ETH balance held in the exchange spot wallet by this adapter
    /// (18-dec internal units, matching the mock ledger scale).
    function getAssetBalance() external view returns (uint256);

    /// @notice Active perp position for `symbol` held by this adapter.
    function getPosition(string calldata symbol) external view returns (
        uint256 size,
        uint256 collateral,
        uint256 entryPrice,
        bool isLong,
        bool isActive
    );

    function getOpenOrderIds() external view returns (bytes32[] memory);
}

contracts/interfaces/ISpotDex.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.28;

/**
 * @title ISpotDex
 * @notice Minimal interface for on-chain spot DEX adapters (Uniswap V3, etc.).
 *
 * Used by the main KashYield contracts to convert between the base asset
 * (wBTC / ETH) and USDC when the perp position P&L doesn't fully cover
 * the Aave debt repayment (typically in a rising-price scenario).
 */
interface ISpotDex {
    /// @notice Swap exactly `amountIn` of `tokenIn` for at least `minAmountOut` of `tokenOut`.
    /// For ETH-in swaps, msg.value must equal amountIn and tokenIn must be address(0).
    /// For ERC-20 inputs, caller must approve this adapter for `amountIn` beforehand.
    /// @param tokenIn      Input token (address(0) = native ETH).
    /// @param tokenOut     Output token.
    /// @param amountIn     Exact input amount.
    /// @param minAmountOut Minimum acceptable output — reverts if not met (slippage guard).
    /// @param recipient    Address to receive the output tokens.
    /// @return amountOut   Actual output received.
    function swapExactIn(
        address tokenIn,
        address tokenOut,
        uint256 amountIn,
        uint256 minAmountOut,
        address recipient
    ) external payable returns (uint256 amountOut);
}

